mapper.select:
select count(0) from  synlte.LABELS

    labelcode = #{labelCode}

        and id != #{id}

        select labelname, labelcode,labellevel,classid  from (select labelname, labelcode,labellevel,classid , row_number() over(partition by
				upper(labelcode)
				  order by moddate desc) rn
					from synlte.LABELS where upper(labelcode) = upper(#{labelCode})
					) where rn =1

select labelname as label, labelcode as value from (select labelname, labelcode , classid,labellevel, row_number() over(partition by upper(labelcode) order by moddate desc) rn from synlte.LABELS
labellevel = #{labelLevel}
and upper(classid) = upper(#{classId})
) where rn =1

select labelname,labelcode , labellevel,classid   from (select labelname,
    labelcode , labellevel,classid ,row_number() over(partition by
    upper(labelcode)
    order by moddate desc) rn
    from synlte.LABELS
    where labelcode in (

            #{item,jdbcType=VARCHAR}

      )
    ) where rn =1
    order by labellevel asc
